            if marker_pos > 0 and marker_pos < end_pos:
                end_pos = marker_pos

        if end_pos != float('inf'):
            section = section[:end_pos]

        # Look for project names in this section
        for line in section.split('\n'):
            line = line.strip()
            if not line or len(line) < 5:
                continue

            # Skip metadata lines  
